mapper.select:
SELECT id,name,latitude,longitude,open_time AS "openTime",close_time AS "closeTime",address,description, raw_description
FROM smoking_point
WHERE id = #{id};

mapper.update:
UPDATE smoking_point
SET name=#{name},latitude=#{latitude},longitude=#{longitude},open_time=#{openTime},close_time=#{closeTime},address=#{address},description=#{description}, raw_description=#{rawDescription}
WHERE id = #{id};
